// ─────────────────────────────────────────────────────────────
// APPROACH 3 — useNavigate  (programmatic / conditional navigation)
// used when navigation depends on logic, not a click on a link
// ─────────────────────────────────────────────────────────────


import React from 'react'
import Login from './components/Login'
import Home from './components/Home'
import Error from './components/Error'
import { Route, Routes } from 'react-router-dom'

function App() {
  return (
    <div>
      <Routes>
        <Route path='/'      element={<Login />} />
        <Route path='/home'  element={<Home />} />
        <Route path='/error' element={<Error />} />

        {/* Login component uses useNavigate to decide where to go after checking credentials */}

        
      </Routes>
    </div>
  )
}

export default App
